#ifndef UART_HAL_H
#define UART_HAL_H

#include <stdint.h>

typedef enum {
    UART_PARITY_NONE = 0,
    UART_PARITY_ODD  = 1,
    UART_PARITY_EVEN = 2
} uart_parity_t;

typedef struct {
    uint32_t baud_rate;
    uint8_t  data_bits;
    uint8_t  stop_bits;
    uart_parity_t parity;
} uart_config_t;

